30		detector := claude.New()
31	
32		// Detect if agent is running
33		running, err := detector.IsRunning()
34		if err != nil {
35			slog.Warn("could not detect agent process", "error", err)
36			running = false
37		}
38	
39		if running {
40			// Quick check: find the latest JSONL path without a full parse and see if
41			// we have already captured this session in a fully-condensed ended state.
42			// This avoids the expensive JSONL parse for stale sessions.
43			latestPath, pathErr := detector.FindLatestJSONLPath(repoRoot)
44			if pathErr == nil {
45				sid := claude.PeekSessionID(latestPath)
46				if shouldSkipSession(filepath.Join(repoRoot, config.PartioDir), sid, latestPath) {
47					slog.Debug("skipping already-condensed ended session", "session_id", sid)
48					running = false
49				}
50			}
51		}
52	
53		var sessionPath string
54		if running {
55			path, _, err := detector.FindLatestSession(repoRoot)
56			if err != nil {
57				slog.Debug("agent running but no session found", "error", err)
58			} else {
59				sessionPath = path
60				slog.Debug("agent session detected", "path", path)
61			}
62		}
63	
64		branch, _ := git.CurrentBranch()
65		commitHash, _ := git.CurrentCommit()
66	
67		state := preCommitState{
68			AgentActive:   running && sessionPath != "",
69			SessionPath:   sessionPath,
70			PreCommitHash: commitHash,
71			Branch:        branch,
72		}
73	
74		// Save state for post-commit
75		stateDir := filepath.Join(repoRoot, config.PartioDir, "state")
76		if err := os.MkdirAll(stateDir, 0o755); err != nil {
77			return err
78		}
79	
80		data, err := json.Marshal(state)
81		if err != nil {
82			return err
83		}
