89	// sessionID has already been fully captured (condensed + ended) and the JSONL
90	// at sessionPath has not been modified since the capture time. Both ENDED and
91	// Condensed must be set; IDLE or ACTIVE sessions are never skipped.
92	func shouldSkipSession(partioDir, sessionID, sessionPath string) bool {
