58				dirs:    map[string][]fileAge{},
59				wantErr: true,
60			},
61		}
62	
63		for _, tt := range tests {
64			t.Run(tt.name, func(t *testing.T) {
65				// Build a fake filesystem:
66				//   tmpDir/home/.claude/projects/<dir>/  — session directories
67				//   tmpDir/repo/child/                   — fake repo root
68				//   tmpDir/repo/                         — parent directory
69				tmpDir := t.TempDir()
70				home := filepath.Join(tmpDir, "home")
